import std.net

// Server example
func start_server() {
    let server = TcpListener.bind("127.0.0.1", 8080)
    let client = server.accept()
    let data = client.receive(1024)
    println("Received: " + data)
    client.send("Hello from server")
    client.close()
    server.close()
}

// Client example
func start_client() {
    let client = TcpSocket.connect("127.0.0.1", 8080)
    client.send("Hello from client")
    let response = client.receive(1024)
    println("Server says: " + response)
    client.close()
}

