main(): Int64 {
    spawn {
        => for (i in 0..10) {
            println("New thread, number = ${i}")
            sleep(100 * Duration.millisecond) /* 睡眠 100 毫秒 */
        }
    }

    for (i in 0..5) {
        println("Main thread, number = ${i}")
        sleep(100 * Duration.millisecond) /* 睡眠 100 毫秒 */
    }
    return 0
}

main(): Int64 {
    let fut: Future<Unit> = spawn {
        => for (i in 0..10) {
            println("New thread, number = ${i}")
            /* 睡眠 100 毫秒 */
            sleep(100 * Duration.millisecond)
        }
    }

    /* 等待线程完成 */
    fut.get()

    for (i in 0..5) {
        println("Main thread, number = ${i}")
        /* 睡眠 100 毫秒 */
        sleep(100 * Duration.millisecond)
    }
    return 0
}

main(): Unit {
    /* 创建线程 */
    let future = spawn {
        while (true) {
            if (Thread.currentThread.hasPendingCancellation) {
                return 0
            }
        }
        return 1
    }
    /* 发起线程取消请求 */
    future.cancel()
    let res = future.get()
    println(res)
}

if (Thread.currentThread.hasPendingCancellation) {
    return 0
}

