@Strategy[start in random<UInt64>()]
@OverflowWrapping
func generateUniqArray(start: UInt64): ArrayList<Int64> {
    let len = 1000
    let rng = Random(start)
    let step = Int64.Max / len
    counter = 0
    ArrayList(
        len,
        {
            _ =>
            counter += rng.nextInt64() % step
            counter
        }
    )
}

