class IntShrink: Shrink<Int> {
    func shrink(value: Int): Iterable<Int> {
        // 返回一系列更小的整数，例如减半
        val list = mutableListOf<Int>()
        var half = value / 2
        while (half != 0) {
            list.add(half)
            half /= 2
        }
        return list
    }
}

// 创建一个 LazySeq，生成斐波那契数列
let fibSeq = LazySeq<Int> { 
    var a = 0
    var b = 1
    return sequence {
        yield(a)
        yield(b)
        while (true) {
            val next = a + b
            yield(next)
            a = b
            b = next
        }
    }
}
