func digest<T>(algorithm: T, data: Array<Byte>): Array<Byte> where T <: Digest {
    // 使用指定算法计算数据的摘要
    return algorithm.compute(data)
}

func digest<T>(algorithm: T, data: String): Array<Byte> where T <: Digest {
    // 使用指定算法计算字符串的摘要（已弃用）
    return algorithm.compute(data.toByteArray())
}

func digest<T>(algorithm: T, stream: InputStream): Array<Byte> where T <: Digest {
    // 使用指定算法计算输入流数据的摘要
    val buffer = ByteArray(1024)
    var bytesRead: Int
    while ((bytesRead = stream.read(buffer)) != -1) {
        algorithm.update(buffer, 0, bytesRead)
    }
    return algorithm.digest()
}

interface Digest {
    // 更新摘要计算的数据
    func update(data: Array<Byte>): Unit
    // 完成摘要计算并返回结果
    func digest(): Array<Byte>
    // 重置摘要计算状态
    func reset(): Unit
}

